import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface HealthRecord {
  id: string;
  date: string;
  height: number; // cm
  weight: number; // kg
  bmi: number;
}

export enum BMIStatus {
  UNDERWEIGHT = 'UNDERWEIGHT',
  NORMAL = 'NORMAL',
  OVERWEIGHT = 'OVERWEIGHT',
  OBESE = 'OBESE'
}

export interface BMIInfo {
  status: BMIStatus;
  label: string;
  color: string;
  advice: string;
}

import { BMIStatus, BMIInfo } from '../types';

export const calculateBMI = (heightCm: number, weightKg: number): number => {
  const heightM = heightCm / 100;
  return parseFloat((weightKg / (heightM * heightM)).toFixed(1));
};

export const getBMIInfo = (bmi: number): BMIInfo => {
  if (bmi < 18.5) {
    return {
      status: BMIStatus.UNDERWEIGHT,
      label: '偏瘦 (Underweight)',
      color: 'text-blue-500',
      advice: '您的体重指数较低。建议适当增加优质蛋白和复合碳水化合物的摄入，并结合适度的力量训练。'
    };
  } else if (bmi < 24) {
    return {
      status: BMIStatus.NORMAL,
      label: '正常 (Normal)',
      color: 'text-green-500',
      advice: '您的各项指标处于理想范围。请继续保持均衡饮食和规律的作息习惯。'
    };
  } else if (bmi < 28) {
    return {
      status: BMIStatus.OVERWEIGHT,
      label: '超重 (Overweight)',
      color: 'text-orange-500',
      advice: '目前体重略微超出理想范围。建议开始轻量级的有氧运动，并减少高糖高脂食物的摄入。'
    };
  } else {
    return {
      status: BMIStatus.OBESE,
      label: '肥胖 (Obese)',
      color: 'text-red-500',
      advice: '您的健康风险可能增加。建议咨询医生制定专业的减脂计划，循序渐进地增加中等强度有氧运动。'
    };
  }
};

import { GoogleGenAI } from "@google/genai";
import { HealthRecord } from "../types";

export const getSmartAdvice = async (records: HealthRecord[]): Promise<string | null> => {
  if (records.length === 0) return null;

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const current = records[0];
    const previous = records.length > 1 ? records[1] : null;

    const prompt = `
      Act as a professional health coach. Based on these body metrics, provide a concise (max 3 sentences) encouraging health advice in Chinese.
      Current Record: Date: ${current.date}, Height: ${current.height}cm, Weight: ${current.weight}kg, BMI: ${current.bmi}.
      ${previous ? `Previous Record: Weight: ${previous.weight}kg, BMI: ${previous.bmi}.` : 'This is the first record.'}
      Focus on trends if applicable. Keep it positive and actionable.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.7,
        topP: 0.9,
      }
    });

    return response.text || "保持记录，您的健康正在一点点积累！";
  } catch (error) {
    console.error("Gemini Advice Error:", error);
    return null;
  }
};

