import React from 'react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { HealthRecord } from '../types';

interface MetricChartProps {
  records: HealthRecord[];
}

const MetricChart: React.FC<MetricChartProps> = ({ records }) => {
  const data = [...records].reverse().map(r => ({
    name: r.date,
    weight: r.weight,
  }));

  if (data.length === 0) {
    return (
      <div className="h-48 flex items-center justify-center text-gray-400 text-sm">
        暂无足够数据展示趋势
      </div>
    );
  }

  return (
    <div className="h-64 w-full">
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart data={data}>
          <defs>
            <linearGradient id="colorWeight" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#007AFF" stopOpacity={0.3}/>
              <stop offset="95%" stopColor="#007AFF" stopOpacity={0}/>
            </linearGradient>
          </defs>
          <CartesianGrid vertical={false} strokeDasharray="3 3" stroke="#E5E5EA" />
          <XAxis 
            dataKey="name" 
            axisLine={false} 
            tickLine={false} 
            tick={{ fontSize: 10, fill: '#8E8E93' }}
            tickFormatter={(val) => val.split('-').slice(1).join('/')}
          />
          <YAxis 
            hide 
            domain={['dataMin - 5', 'dataMax + 5']} 
          />
          <Tooltip 
            contentStyle={{ 
              borderRadius: '16px', 
              border: 'none', 
              boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
              fontSize: '12px'
            }}
          />
          <Area 
            type="monotone" 
            dataKey="weight" 
            stroke="#007AFF" 
            strokeWidth={3}
            fillOpacity={1} 
            fill="url(#colorWeight)" 
            animationDuration={1500}
          />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

export default MetricChart;

import React, { useState, useEffect, useCallback } from 'react';
import { Plus, Trash2, TrendingDown, TrendingUp, Info, Activity } from 'lucide-react';
import Layout from './components/Layout';
import MetricChart from './components/MetricChart';
import { HealthRecord } from './types';
import { calculateBMI, getBMIInfo } from './utils/bmi';
import { getSmartAdvice } from './services/geminiService';

const STORAGE_KEY = 'health_records_v1';

const App: React.FC = () => {
  const [records, setRecords] = useState<HealthRecord[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [smartAdvice, setSmartAdvice] = useState<string | null>(null);
  const [isLoadingAdvice, setIsLoadingAdvice] = useState(false);

  // Form State
  const [weight, setWeight] = useState<string>('');
  const [height, setHeight] = useState<string>('');
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);

  // Load data on mount
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setRecords(parsed);
      } catch (e) {
        console.error("Failed to parse local storage", e);
      }
    }
  }, []);

  // Save data whenever records change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(records));
  }, [records]);

  // Fetch smart advice when records change
  useEffect(() => {
    const fetchAdvice = async () => {
      if (records.length > 0) {
        setIsLoadingAdvice(true);
        const advice = await getSmartAdvice(records);
        setSmartAdvice(advice);
        setIsLoadingAdvice(false);
      } else {
        setSmartAdvice(null);
      }
    };
    fetchAdvice();
  }, [records]);

  const addRecord = () => {
    const w = parseFloat(weight);
    const h = parseFloat(height);
    if (!w || !h) return;

    const newRecord: HealthRecord = {
      id: Date.now().toString(),
      date,
      height: h,
      weight: w,
      bmi: calculateBMI(h, w)
    };

    setRecords(prev => [newRecord, ...prev].sort((a, b) => b.date.localeCompare(a.date)));
    setIsModalOpen(false);
    setWeight('');
  };

  const deleteRecord = (id: string) => {
    setRecords(prev => prev.filter(r => r.id !== id));
  };

  const currentRecord = records[0];
  const previousRecord = records[1];
  const weightDiff = currentRecord && previousRecord ? currentRecord.weight - previousRecord.weight : 0;
  const bmiInfo = currentRecord ? getBMIInfo(currentRecord.bmi) : null;

  return (
    <Layout>
      <header className="mb-8">
        <h1 className="text-4xl font-bold tracking-tight text-gray-900">Health Pro</h1>
        <p className="text-gray-500 font-medium">身体数据追踪与建议</p>
      </header>

      {/* Hero Stats Card */}
      {currentRecord ? (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
          <div className="glass-card rounded-[32px] p-6 shadow-sm">
            <div className="flex justify-between items-start mb-4">
              <span className="text-sm font-semibold text-gray-400 uppercase tracking-wider">当前体重</span>
              <Activity size={20} className="text-blue-500" />
            </div>
            <div className="flex items-baseline gap-2">
              <span className="text-4xl font-bold text-gray-900">{currentRecord.weight}</span>
              <span className="text-lg text-gray-500 font-medium">kg</span>
            </div>
            <div className={`mt-2 flex items-center gap-1 text-sm font-semibold ${weightDiff > 0 ? 'text-red-500' : weightDiff < 0 ? 'text-green-500' : 'text-gray-400'}`}>
              {weightDiff > 0 ? <TrendingUp size={16} /> : weightDiff < 0 ? <TrendingDown size={16} /> : null}
              {weightDiff === 0 ? '无变化' : `${Math.abs(weightDiff).toFixed(1)} kg`}
              <span className="text-gray-400 font-normal ml-1">自上次记录</span>
            </div>
          </div>

          <div className="glass-card rounded-[32px] p-6 shadow-sm">
            <div className="flex justify-between items-start mb-4">
              <span className="text-sm font-semibold text-gray-400 uppercase tracking-wider">BMI 指数</span>
              <Info size={20} className="text-purple-500" />
            </div>
            <div className="flex items-baseline gap-2">
              <span className="text-4xl font-bold text-gray-900">{currentRecord.bmi}</span>
              <span className={`text-sm font-bold px-2 py-0.5 rounded-full bg-white/50 ${bmiInfo?.color}`}>
                {bmiInfo?.label}
              </span>
            </div>
            <p className="mt-3 text-sm text-gray-500 leading-relaxed italic">
              {bmiInfo?.status === 'NORMAL' ? '您的体型非常标准，请继续保持！' : '体型存在优化空间，查看下方AI建议。'}
            </p>
          </div>
        </div>
      ) : (
        <div className="glass-card rounded-[32px] p-12 text-center mb-6">
          <Activity size={48} className="mx-auto text-blue-200 mb-4" />
          <h2 className="text-xl font-bold text-gray-900 mb-2">欢迎使用 Health Pro</h2>
          <p className="text-gray-500 mb-6">点击下方加号开始录入您的第一条身体数据</p>
        </div>
      )}

      {/* Smart Advice Section */}
      {records.length > 0 && (
        <div className="glass-card rounded-[32px] p-6 mb-6 border-l-4 border-l-blue-500">
          <h3 className="text-sm font-bold text-gray-400 uppercase mb-3 tracking-wider flex items-center gap-2">
            ✨ AI 健康建议
            {isLoadingAdvice && <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse" />}
          </h3>
          <p className="text-gray-700 leading-relaxed font-medium">
            {smartAdvice || bmiInfo?.advice || "正在同步您的健康数据..."}
          </p>
        </div>
      )}

      {/* Charts Section */}
      {records.length > 1 && (
        <div className="glass-card rounded-[32px] p-6 mb-6">
          <h3 className="text-sm font-bold text-gray-400 uppercase mb-4 tracking-wider">体重趋势 (Trend)</h3>
          <MetricChart records={records} />
        </div>
      )}

      {/* History List */}
      <div className="mb-6">
        <div className="flex justify-between items-center mb-4 px-2">
          <h3 className="text-lg font-bold text-gray-900">历史记录</h3>
          <span className="text-xs text-gray-400 font-medium">{records.length} 条记录</span>
        </div>
        <div className="space-y-3">
          {records.map((r) => (
            <div key={r.id} className="bg-white rounded-2xl p-4 flex justify-between items-center shadow-sm group">
              <div>
                <div className="flex items-center gap-2 mb-1">
                  <span className="text-sm font-bold text-gray-900">{r.weight} kg</span>
                  <span className="text-[10px] px-2 py-0.5 rounded-full bg-gray-100 text-gray-500">BMI {r.bmi}</span>
                </div>
                <p className="text-xs text-gray-400">{r.date} • {r.height}cm</p>
              </div>
              <button 
                onClick={() => deleteRecord(r.id)}
                className="p-2 text-gray-300 hover:text-red-500 transition-colors"
              >
                <Trash2 size={18} />
              </button>
            </div>
          ))}
        </div>
      </div>

      {/* Floating Action Button */}
      <button 
        onClick={() => setIsModalOpen(true)}
        className="fixed bottom-10 right-10 w-16 h-16 bg-blue-600 text-white rounded-full shadow-2xl flex items-center justify-center hover:bg-blue-700 transition-all active:scale-90 z-40"
      >
        <Plus size={32} />
      </button>

      {/* Simple Modal Overlay */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center p-4 bg-black/40 backdrop-blur-sm">
          <div className="bg-white w-full max-w-md rounded-[40px] p-8 shadow-2xl animate-in slide-in-from-bottom duration-300">
            <h2 className="text-2xl font-bold mb-6 text-gray-900 text-center">录入身体指标</h2>

            <div className="space-y-6">
              <div>
                <label className="block text-xs font-bold text-gray-400 uppercase mb-2 ml-1">日期 (Date)</label>
                <input 
                  type="date"
                  value={date}
                  onChange={(e) => setDate(e.target.value)}
                  className="w-full bg-gray-50 rounded-2xl p-4 text-gray-900 border-none outline-none ring-2 ring-transparent focus:ring-blue-500 transition-all"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-gray-400 uppercase mb-2 ml-1">身高 (cm)</label>
                  <input 
                    type="number" 
                    placeholder="175"
                    value={height}
                    onChange={(e) => setHeight(e.target.value)}
                    className="w-full bg-gray-50 rounded-2xl p-4 text-gray-900 border-none outline-none ring-2 ring-transparent focus:ring-blue-500 transition-all"
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-gray-400 uppercase mb-2 ml-1">体重 (kg)</label>
                  <input 
                    type="number"
                    step="0.1" 
                    placeholder="70.5"
                    value={weight}
                    onChange={(e) => setWeight(e.target.value)}
                    className="w-full bg-gray-50 rounded-2xl p-4 text-gray-900 border-none outline-none ring-2 ring-transparent focus:ring-blue-500 transition-all"
                  />
                </div>
              </div>

              <div className="flex gap-4 pt-4">
                <button 
                  onClick={() => setIsModalOpen(false)}
                  className="flex-1 py-4 text-gray-500 font-bold hover:bg-gray-100 rounded-3xl transition-all"
                >
                  取消
                </button>
                <button 
                  onClick={addRecord}
                  disabled={!weight || !height}
                  className="flex-1 py-4 bg-blue-600 text-white font-bold rounded-3xl shadow-lg hover:bg-blue-700 transition-all disabled:opacity-50"
                >
                  保存记录
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

