import React from 'react';
import { HealthRecord } from '../types';

interface MetricChartProps {
  records: HealthRecord[];
}

const MetricChart: React.FC<MetricChartProps> = ({ records }) => {
  // Sort records by date for the chart
  const data = [...records]
    .sort((a, b) => a.date.localeCompare(b.date))
    .slice(-7); // Show last 7 entries

  if (data.length < 2) {
    return (
      <div className="h-40 flex flex-col items-center justify-center text-gray-400 space-y-2">
        <div className="w-full h-[2px] bg-gray-100 relative">
          <div className="absolute left-1/2 -translate-x-1/2 -top-1 w-2 h-2 bg-gray-200 rounded-full"></div>
        </div>
        <p className="text-[10px] font-bold uppercase tracking-widest">需要至少两条记录生成趋势</p>
      </div>
    );
  }

  const width = 300;
  const height = 150;
  const padding = 20;

  const weights = data.map(d => d.weight);
  const minWeight = Math.min(...weights) - 1;
  const maxWeight = Math.max(...weights) + 1;
  const weightRange = maxWeight - minWeight;

  const getX = (index: number) => padding + (index * (width - 2 * padding) / (data.length - 1));
  const getY = (weight: number) => height - (padding + ((weight - minWeight) * (height - 2 * padding) / weightRange));

  const points = data.map((d, i) => `${getX(i)},${getY(d.weight)}`).join(' ');
  const areaPoints = `${getX(0)},${height} ` + points + ` ${getX(data.length - 1)},${height}`;

  return (
    <div className="w-full">
      <svg viewBox={`0 0 ${width} ${height}`} className="w-full h-auto overflow-visible">
        <defs>
          <linearGradient id="areaGradient" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor="#007AFF" stopOpacity="0.3" />
            <stop offset="100%" stopColor="#007AFF" stopOpacity="0" />
          </linearGradient>
        </defs>

        {/* Horizontal Grid Lines */}
        {[0, 0.5, 1].map((p, i) => {
          const y = padding + p * (height - 2 * padding);
          return <line key={i} x1={padding} y1={y} x2={width - padding} y2={y} stroke="#F2F2F7" strokeWidth="1" />;
        })}

        {/* Area Fill */}
        <polygon points={areaPoints} fill="url(#areaGradient)" />

        {/* Line Path */}
        <polyline
          fill="none"
          stroke="#007AFF"
          strokeWidth="3"
          strokeLinecap="round"
          strokeLinejoin="round"
          points={points}
          className="animate-[dash_2s_ease-in-out]"
        />

        {/* Data Dots */}
        {data.map((d, i) => (
          <g key={d.id}>
            <circle cx={getX(i)} cy={getY(d.weight)} r="4" fill="#007AFF" />
            <circle cx={getX(i)} cy={getY(d.weight)} r="2" fill="white" />
            <text 
              x={getX(i)} 
              y={getY(d.weight) - 8} 
              textAnchor="middle" 
              fontSize="8" 
              fontWeight="bold" 
              fill="#8E8E93"
            >
              {d.weight}
            </text>
          </g>
        ))}

        {/* X-Axis Labels */}
        {data.map((d, i) => (
          <text 
            key={i} 
            x={getX(i)} 
            y={height} 
            textAnchor="middle" 
            fontSize="7" 
            fontWeight="bold" 
            fill="#C7C7CC"
          >
            {d.date.split('-').slice(1).join('/')}
          </text>
        ))}
      </svg>
    </div>
  );
};

export default MetricChart;

