        )}
      </header>

      {currentRecord ? (
        <div className="space-y-4 animate-fade-in">
          {/* Key Metrics */}
          <div className="grid grid-cols-2 gap-4">
            <div className="glass-card rounded-[32px] p-6">
              <div className="flex items-center gap-2 mb-4 text-gray-400">
