下面是flutter加载这个你的reac-web项目的核心代码，我看这个代码好像是本地起了一个服务器，请帮我看下这个思路是否正确，目前在安卓上能够正常展示，就是在iOS手机上存在样式错误。

import 'dart:io';
import 'dart:async';
import 'dart:convert';
import 'package:flutter/material.dart';
import 'package:webview_flutter/webview_flutter.dart';
import 'package:webview_flutter_android/webview_flutter_android.dart';
import 'package:provider/provider.dart';
import 'package:path/path.dart' as p;
import '../models/my_project.dart';
import '../models/app_state.dart';
import '../l10n/s.dart';

class ViewerPage extends StatefulWidget {
  final MyProject myProject;
  const ViewerPage({super.key, required this.myProject});

  @override
  State<ViewerPage> createState() => _ViewerPageState();
}

class _ViewerPageState extends State<ViewerPage> {
  late final WebViewController _controller;
  bool _isLoading = true;
  String? _error;
  HttpServer? _server;

  @override
  void initState() {
    super.initState();
    _initController();
    _startLocalServerAndLoad();
  }

  void _initController() {
    _controller = WebViewController()
      ..setJavaScriptMode(JavaScriptMode.unrestricted)
      ..setNavigationDelegate(
        NavigationDelegate(
          onPageFinished: (String url) {
            if (mounted) setState(() => _isLoading = false);
            // 终极适配：注入 CSS 变量和 Viewport，确保 React 样式能正确计算高度和边距
            _controller.runJavaScript("""
              // 1. 修复状态栏重叠
              var style = document.createElement('style');
              style.innerHTML = 'body { padding-top: env(safe-area-inset-top); }';
              document.head.appendChild(style);

              // 2. 确保 Viewport 包含 viewport-fit=cover
              var meta = document.querySelector('meta[name="viewport"]');
              if (meta) {
                var content = meta.getAttribute('content');
                if (!content.includes('viewport-fit=cover')) {
                  meta.setAttribute('content', content + ', viewport-fit=cover');
                }
              }
            """);
          },
          onWebResourceError: (WebResourceError error) {
            debugPrint("WebView Error: [${error.errorCode}] ${error.description}");
          },
        ),
      )
      ..setOnConsoleMessage((JavaScriptConsoleMessage message) {
        debugPrint("WebView Console: [${message.level.name}] ${message.message}");
      });

    if (_controller.platform is AndroidWebViewController) {
      (_controller.platform as AndroidWebViewController).setAllowFileAccess(true);
      (_controller.platform as AndroidWebViewController).setAllowContentAccess(true);
    }
  }

  Future<void> _startLocalServerAndLoad() async {
    try {
      final state = context.read<AppState>();
      final projectDir = await state.getProjectDirectory(widget.myProject.id);

      // 启动前再次确认文件清单
      final files = Directory(projectDir).listSync(recursive: true);
      debugPrint("--- Current Project Files ---");
      for (var f in files) if (f is File) debugPrint("File: ${p.relative(f.path, from: projectDir)} (${f.lengthSync()} bytes)");
      debugPrint("----------------------------");

      _server = await HttpServer.bind(InternetAddress.loopbackIPv4, 0);
      final port = _server!.port;

      _server!.listen((HttpRequest request) async {
        try {
          String reqPath = Uri.decodeComponent(request.uri.path);
          if (reqPath == '/') reqPath = '/${widget.myProject.content}';
          if (reqPath.startsWith('/')) reqPath = reqPath.substring(1);

          // 记录每一次请求，帮助定位丢失的资源
          debugPrint("Server Request: $reqPath");

          File file = File(p.join(projectDir, reqPath));

          if (!await file.exists()) {
            final String ext = p.extension(reqPath).toLowerCase();
            final String targetBaseName = p.basenameWithoutExtension(reqPath).toLowerCase();

            try {
              final allFiles = Directory(projectDir).listSync(recursive: true);
              File? fallback;
              File? firstSameExtFile;

              for (var f in allFiles) {
                if (f is File) {
                  final String fName = p.basename(f.path).toLowerCase();
                  final String fExt = p.extension(f.path).toLowerCase();
                  final String fBaseName = p.basenameWithoutExtension(f.path).toLowerCase();

                  if (fExt == ext) firstSameExtFile ??= f;

                  if (fName == p.basename(reqPath).toLowerCase() || 
                      ((ext == '.css' || ext == '.js') && fBaseName.startsWith(targetBaseName) && fExt == ext)) {
                    fallback = f;
                    break;
                  }
                }
              }
              file = fallback ?? (ext == '.css' ? firstSameExtFile : null) ?? file;
            } catch (e) {}
          }

          if (await file.exists()) {
            final mimeType = _getMimeType(file.path);
            request.response.headers.contentType = ContentType.parse(mimeType);
            request.response.headers.add("Access-Control-Allow-Origin", "*");
            request.response.add(await file.readAsBytes());
          } else {
            if (reqPath.endsWith('.css') || reqPath.endsWith('.js')) {
              request.response.statusCode = HttpStatus.ok;
              request.response.headers.contentType = ContentType.parse(reqPath.endsWith('.css') ? 'text/css' : 'text/javascript');
              request.response.write(""); 
              debugPrint("Server: [Stub Response] $reqPath (Resource missing)");
            } else {
              request.response.statusCode = HttpStatus.notFound;
            }
          }
        } catch (e) {
          request.response.statusCode = HttpStatus.internalServerError;
        } finally {
          await request.response.close();
        }
      });

      final entryUrl = "http://127.0.0.1:$port/";
      debugPrint("Project starting at: $entryUrl");
      await _controller.loadRequest(Uri.parse(entryUrl));

    } catch (e) {
      if (mounted) setState(() => _error = "Server error: $e");
    }
  }

  String _getMimeType(String filePath) {
    final ext = p.extension(filePath).toLowerCase();
    switch (ext) {
      case '.html': return 'text/html; charset=utf-8';
      case '.js': return 'text/javascript';
      case '.mjs': return 'text/javascript';
      case '.css': return 'text/css';
      case '.png': return 'image/png';
      case '.jpg':
      case '.jpeg': return 'image/jpeg';
      case '.gif': return 'image/gif';
      case '.svg': return 'image/svg+xml';
      case '.json': return 'application/json';
      default: return 'application/octet-stream';
    }
  }

  @override
  void dispose() {
    _server?.close(force: true);
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final s = S.of(context);
    final isDark = Theme.of(context).brightness == Brightness.dark;

    return Scaffold(
      backgroundColor: isDark ? Colors.black : Colors.white,
      body: Stack(
        children: [
          WebViewWidget(controller: _controller),
          Positioned(
            left: 16,
            top: MediaQuery.of(context).padding.top + 4,
            child: GestureDetector(
              onTap: () async {
                if (await _controller.canGoBack()) await _controller.goBack();
                else if (mounted) Navigator.pop(context);
              },
              child: Container(
                width: 32, height: 32,
                decoration: BoxDecoration(
                  color: isDark ? Colors.black.withOpacity(0.2) : Colors.white.withOpacity(0.5),
                  shape: BoxShape.circle,
                ),
                child: Icon(Icons.arrow_back_ios_new, size: 16, color: isDark ? Colors.white70 : Colors.black54),
              ),
            ),
          ),
          if (_isLoading) Container(color: isDark ? Colors.black : Colors.white, child: const Center(child: CircularProgressIndicator())),
          if (_error != null) Center(child: Text(_error!)),
        ],
      ),
    );
  }
}

