import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import { 
  Plus, Trash2, TrendingDown, TrendingUp, Activity, 
  Scale, Calendar, ChevronRight, Zap, BarChart3, 
  ChevronDown, X, Info
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

// --- Types & Constants ---
interface HealthRecord {
  id: string;
  date: string;
  height: number;
  weight: number;
  bmi: number;
}

const STORAGE_KEY = 'health_pro_data_v1';

// --- Utilities ---
const calculateBMI = (h: number, w: number) => parseFloat((w / ((h / 100) ** 2)).toFixed(1));

const getBMIInfo = (bmi: number) => {
  if (bmi < 18.5) return { label: '偏瘦', color: 'text-blue-500', advice: '建议增加蛋白质摄入。' };
  if (bmi < 24) return { label: '正常', color: 'text-green-500', advice: '非常棒，请继续保持！' };
  if (bmi < 28) return { label: '超重', color: 'text-orange-500', advice: '建议控制热量，增加运动。' };
  return { label: '肥胖', color: 'text-red-500', advice: '为了健康，请考虑咨询医生。' };
};

// --- Components ---

// 1. Chart Component
const MetricChart = ({ records, mode, selectedYear }: { records: HealthRecord[], mode: string, selectedYear: string }) => {
  const chartData = useMemo(() => {
    if (records.length < 1) return [];
    let filtered = [...records].sort((a, b) => a.date.localeCompare(b.date));

    if (mode === 'monthly') {
      const year = selectedYear === 'all' ? filtered[filtered.length - 1].date.substring(0, 4) : selectedYear;
      filtered = filtered.filter(r => r.date.startsWith(year));
    } else if (mode === 'yearly' && selectedYear !== 'all') {
      filtered = filtered.filter(r => r.date.startsWith(selectedYear));
    }

    if (mode === 'recent') {
      return filtered.slice(-7).map(r => ({ label: r.date.split('-').slice(1).join('/'), weight: r.weight, id: r.id }));
    }

    const groups: Record<string, number[]> = {};
    filtered.forEach(r => {
      const key = mode === 'monthly' ? r.date.substring(5, 7) + '月' : r.date.substring(0, 4) + '年';
      if (!groups[key]) groups[key] = [];
      groups[key].push(r.weight);
    });

    return Object.keys(groups).map(key => ({
      label: key,
      weight: parseFloat((groups[key].reduce((a, b) => a + b, 0) / groups[key].length).toFixed(1)),
      id: key
    }));
  }, [records, mode, selectedYear]);

  if (chartData.length < 2) {
    return (
      <div className="h-40 flex flex-col items-center justify-center text-gray-300">
        <Info size={24} className="mb-2 opacity-20" />
        <p className="text-[10px] font-bold tracking-widest uppercase">需要至少两条记录生成趋势</p>
      </div>
    );
  }

  const weights = chartData.map(d => d.weight);
  const minW = Math.min(...weights);
  const maxW = Math.max(...weights);
  const range = (maxW - minW) || 10;
  const yMin = minW - range * 0.2;
  const yMax = maxW + range * 0.2;

  const width = 300;
  const height = 150;
  const pad = 30;

  const getX = (i: number) => pad + (i * (width - 2 * pad) / (chartData.length - 1));
  const getY = (w: number) => height - pad - ((w - yMin) * (height - 2 * pad) / (yMax - yMin));

  const points = chartData.map((d, i) => `${getX(i)},${getY(d.weight)}`).join(' ');

  return (
    <svg viewBox={`0 0 ${width} ${height}`} className="w-full h-auto overflow-visible mt-4">
      <defs>
        <linearGradient id="chartFill" x1="0" y1="0" x2="0" y2="1">
