import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import { 
  Plus, Trash2, TrendingDown, TrendingUp, Activity, 
  Scale, Calendar, ChevronRight, Zap, BarChart3, 
  ChevronDown, X, Info, Heart
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

// --- 配置与常量 ---
interface HealthRecord {
  id: string;
  date: string;
  height: number;
  weight: number;
  bmi: number;
}

const STORAGE_KEY = 'ios_local_health_v1';

// --- 工具函数 ---
const calculateBMI = (h: number, w: number) => parseFloat((w / ((h / 100) ** 2)).toFixed(1));

const getBMIInfo = (bmi: number) => {
  if (bmi < 18.5) return { label: '偏瘦', color: 'text-blue-500', bg: 'bg-blue-50', advice: '建议增加蛋白质与营养摄入。' };
  if (bmi < 24) return { label: '正常', color: 'text-green-500', bg: 'bg-green-50', advice: '状态极佳，请继续保持！' };
  if (bmi < 28) return { label: '超重', color: 'text-orange-500', bg: 'bg-orange-50', advice: '建议控制饮食，增加日常运动。' };
  return { label: '肥胖', color: 'text-red-500', bg: 'bg-red-50', advice: '请关注心血管健康，必要时咨询专家。' };
};

// --- 组件：趋势图表 ---
const HealthChart = ({ records, mode, year }: { records: HealthRecord[], mode: string, year: string }) => {
  const data = useMemo(() => {
    if (records.length < 1) return [];
    let sorted = [...records].sort((a, b) => a.date.localeCompare(b.date));

    if (mode === 'monthly') {
      const targetYear = year === 'all' ? sorted[sorted.length-1].date.split('-')[0] : year;
      sorted = sorted.filter(r => r.date.startsWith(targetYear));
    }

    if (mode === 'recent') {
      return sorted.slice(-7).map(r => ({ x: r.date.slice(5), y: r.weight, id: r.id }));
    }

    const groups: Record<string, number[]> = {};
    sorted.forEach(r => {
      const key = mode === 'monthly' ? r.date.slice(5, 7) + '月' : r.date.slice(0, 4) + '年';
      if (!groups[key]) groups[key] = [];
      groups[key].push(r.weight);
    });

    return Object.keys(groups).map(k => ({
      x: k,
      y: parseFloat((groups[k].reduce((a, b) => a + b, 0) / groups[k].length).toFixed(1)),
      id: k
    }));
  }, [records, mode, year]);

  if (data.length < 2) {
    return (
      <div className="h-40 flex flex-col items-center justify-center text-gray-300 bg-gray-50/50 rounded-2xl">
        <BarChart3 size={32} className="mb-2 opacity-20" />
        <p className="text-[10px] font-bold tracking-widest opacity-40">数据不足以生成趋势线</p>
      </div>
    );
  }

  const weights = data.map(d => d.y);
  const min = Math.min(...weights) * 0.95;
  const max = Math.max(...weights) * 1.05;
  const range = max - min;

  const w = 300, h = 120, p = 25;
  const getX = (i: number) => p + (i * (w - 2 * p) / (data.length - 1));
  const getY = (val: number) => h - p - ((val - min) * (h - 2 * p) / range);

  const path = data.map((d, i) => `${getX(i)},${getY(d.y)}`).join(' ');
  const area = `${getX(0)},${h - p} ${path} ${getX(data.length - 1)},${h - p}`;

  return (
    <svg viewBox={`0 0 ${w} ${h}`} className="w-full mt-2 overflow-visible">
      <defs>
        <linearGradient id="g" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor="#007AFF" stopOpacity="0.15" />
          <stop offset="100%" stopColor="#007AFF" stopOpacity="0" />
        </linearGradient>
      </defs>
      <polygon points={area} fill="url(#g)" />
      <polyline points={path} fill="none" stroke="#007AFF" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" />
      {data.map((d, i) => (
        <g key={d.id}>
          <circle cx={getX(i)} cy={getY(d.y)} r="3" fill="#007AFF" />
          <text x={getX(i)} y={h - 5} textAnchor="middle" fontSize="6" fill="#8E8E93" fontWeight="bold">{d.x}</text>
          <text x={getX(i)} y={getY(d.y) - 8} textAnchor="middle" fontSize="7" fill="#1C1C1E" fontWeight="bold">{d.y}</text>
        </g>
      ))}
    </svg>
  );
};

