              <h2 className="text-2xl font-black">录入身体指标</h2>
              <button onClick={() => setIsModalOpen(false)} className="bg-gray-100 p-2 rounded-full text-gray-400"><X size={20}/></button>
            </div>

            <div className="space-y-6">
              <div className="bg-gray-50 rounded-2xl p-4">
                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1">记录日期</label>
                <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full bg-transparent text-lg font-black outline-none" />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="bg-gray-50 rounded-2xl p-4">
                  <label className="block text-[10px] font-black text-gray-400 uppercase mb-1">身高 (cm)</label>
                  <input type="number" value={height} onChange={e => setHeight(e.target.value)} placeholder="170" className="w-full bg-transparent text-lg font-black outline-none" />
                </div>
                <div className="bg-gray-50 rounded-2xl p-4">
                  <label className="block text-[10px] font-black text-gray-400 uppercase mb-1">体重 (kg)</label>
                  <input type="number" step="0.1" value={weight} onChange={e => setWeight(e.target.value)} placeholder="60.0" className="w-full bg-transparent text-lg font-black outline-none" />
                </div>
              </div>

              {height && weight && (
                <div className="p-4 bg-blue-50 rounded-2xl flex justify-between items-center">
                  <span className="text-[10px] font-black text-blue-600 uppercase">实时 BMI</span>
                  <span className="text-2xl font-black text-blue-700">{calculateBMI(parseFloat(height), parseFloat(weight))}</span>
                </div>
              )}

              <button 
                onClick={handleSave}
                disabled={!weight || !height}
                className="w-full py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl disabled:opacity-30 active:scale-95 transition-all flex items-center justify-center gap-2"
              >
                存入档案 <ChevronRight size={18} />
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

