import './style.css'; // 关键：引入本地 CSS
import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import { 
  Plus, Trash2, TrendingDown, TrendingUp, Activity, 
  Scale, Calendar, ChevronRight, Zap, BarChart3, 
  ChevronDown, X, Heart
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

// --- Types ---
interface HealthRecord {
  id: string;
  date: string;
  height: number;
  weight: number;
  bmi: number;
}

const STORAGE_KEY = 'local_health_v2_db';

// --- Utils ---
const calculateBMI = (h: number, w: number) => parseFloat((w / ((h / 100) ** 2)).toFixed(1));

const getBMIInfo = (bmi: number) => {
  if (bmi < 18.5) return { label: '偏瘦', color: 'text-blue-500', bg: 'bg-blue-50', advice: '建议增加优质营养。' };
  if (bmi < 24) return { label: '正常', color: 'text-green-500', bg: 'bg-green-50', advice: '状态极佳，请保持！' };
  if (bmi < 28) return { label: '超重', color: 'text-orange-500', bg: 'bg-orange-50', advice: '建议适度有氧运动。' };
  return { label: '肥胖', color: 'text-red-500', bg: 'bg-red-50', advice: '请关注健康风险，控制饮食。' };
};

// --- SVG Chart Component ---
const LocalChart = ({ records, mode, year }: { records: HealthRecord[], mode: string, year: string }) => {
  const data = useMemo(() => {
    if (records.length < 1) return [];
    let list = [...records].sort((a, b) => a.date.localeCompare(b.date));

    if (mode === 'monthly' && year !== 'all') {
      list = list.filter(r => r.date.startsWith(year));
    }

    if (mode === 'recent') {
      return list.slice(-7).map(r => ({ x: r.date.slice(5), y: r.weight, id: r.id }));
    }

    const groups: Record<string, number[]> = {};
    list.forEach(r => {
      const key = mode === 'monthly' ? r.date.slice(5, 7) + '月' : r.date.slice(0, 4) + '年';
      if (!groups[key]) groups[key] = [];
      groups[key].push(r.weight);
    });

    return Object.keys(groups).map(k => ({
      x: k,
      y: parseFloat((groups[k].reduce((a, b) => a + b, 0) / groups[k].length).toFixed(1)),
      id: k
    }));
  }, [records, mode, year]);

  if (data.length < 2) {
    return (
      <div className="h-40 flex flex-col items-center justify-center bg-gray-50/50 rounded-3xl text-gray-300">
        <BarChart3 size={24} className="mb-2 opacity-30" />
        <span className="text-[10px] font-black uppercase tracking-widest opacity-40">数据点不足</span>
      </div>
    );
  }

  const weights = data.map(d => d.y);
  const min = Math.min(...weights) * 0.98;
  const max = Math.max(...weights) * 1.02;
  const range = max - min;
  const w = 300, h = 120, p = 25;

  const getX = (i: number) => p + (i * (w - 2 * p) / (data.length - 1));
  const getY = (v: number) => h - p - ((v - min) * (h - 2 * p) / range);

  const path = data.map((d, i) => `${getX(i)},${getY(d.y)}`).join(' ');

  return (
    <svg viewBox={`0 0 ${w} ${h}`} className="w-full mt-4 overflow-visible">
      <defs>
        <linearGradient id="localGradient" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor="#007AFF" stopOpacity="0.15" />
          <stop offset="100%" stopColor="#007AFF" stopOpacity="0" />
        </linearGradient>
      </defs>
      <polygon points={`${getX(0)},${h-p} ${path} ${getX(data.length-1)},${h-p}`} fill="url(#localGradient)" />
      <polyline points={path} fill="none" stroke="#007AFF" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" />
      {data.map((d, i) => (
        <g key={d.id}>
          <circle cx={getX(i)} cy={getY(d.y)} r="3.5" fill="#007AFF" stroke="white" strokeWidth="1.5" />
          <text x={getX(i)} y={h - 5} textAnchor="middle" fontSize="6" fill="#8E8E93" fontWeight="bold">{d.x}</text>
          <text x={getX(i)} y={getY(d.y) - 8} textAnchor="middle" fontSize="7" fill="#1C1C1E" fontWeight="black">{d.y}</text>
        </g>
      ))}
    </svg>
  );
};

// --- App Component ---
const App = () => {
  const [records, setRecords] = useState<HealthRecord[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [chartMode, setChartMode] = useState('recent');
  const [selectedYear, setSelectedYear] = useState('all');
  const [aiAdvice, setAiAdvice] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);

  // Form
  const [weight, setWeight] = useState('');
  const [height, setHeight] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      const p = JSON.parse(saved);
      setRecords(p);
      if (p.length > 0) setHeight(p[0].height.toString());
    }
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(records));
    if (records.length > 0) fetchAdvice();
  }, [records]);

  const fetchAdvice = async () => {
    if (!process.env.API_KEY || records.length === 0) return;
    setIsAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const cur = records[0];
      const prompt = `你是健康教练。身高${cur.height}cm, 体重${cur.weight}kg, BMI ${cur.bmi}。用中文给1条20字内极简健康建议。`;
      const res = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt });
      setAiAdvice(res.text);
    } catch (e) {
      console.error(e);
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleSave = () => {
    const w = parseFloat(weight), h = parseFloat(height);
    if (!w || !h) return;
    const nr = { id: Date.now().toString(), date, height: h, weight: w, bmi: calculateBMI(h, w) };
    setRecords(prev => [nr, ...prev].sort((a, b) => b.date.localeCompare(a.date)));
    setIsModalOpen(false);
    setWeight('');
  };

  const cur = records[0];
  const diff = cur && records[1] ? cur.weight - records[1].weight : 0;
  const bmi = cur ? getBMIInfo(cur.bmi) : null;
  const years = Array.from(new Set(records.map(r => r.date.split('-')[0]))).sort().reverse();

  return (
    <div className="max-w-md mx-auto px-6 pb-24 min-h-screen">
      <div className="safe-area-top-left" />

      <header className="pt-20 mb-8 animate-ios-fade">
        <div className="flex items-center gap-2 mb-1">
          <Heart className="text-red-500 fill-red-500" size={24} />
          <h1 className="text-3xl font-black tracking-tighter">Health Pro</h1>
        </div>
        <p className="text-gray-400 font-bold text-xs uppercase tracking-[0.2em]">本地身体指标档案</p>
      </header>

      {cur ? (
        <div className="space-y-6 animate-ios-fade">
          {/* 大数字卡片 */}
          <div className="grid grid-cols-2 gap-4">
            <div className="glass-card rounded-[32px] p-6 ios-active">
              <div className="flex items-center gap-2 mb-4 text-gray-400">
                <Scale size={16} />
                <span className="text-[10px] font-black uppercase">体重</span>
              </div>
              <div className="flex items-baseline gap-1">
                <span className="text-4xl font-black">{cur.weight}</span>
                <span className="text-xs font-bold text-gray-300">kg</span>
              </div>
              <div className={`mt-2 flex items-center gap-1 text-[11px] font-black ${diff > 0 ? 'text-red-500' : diff < 0 ? 'text-green-500' : 'text-gray-300'}`}>
                {diff !== 0 && (diff > 0 ? <TrendingUp size={12}/> : <TrendingDown size={12}/>)}
                {diff === 0 ? '稳定' : `${Math.abs(diff).toFixed(1)}kg`}
              </div>
            </div>

            <div className="glass-card rounded-[32px] p-6 ios-active">
              <div className="flex items-center gap-2 mb-4 text-gray-400">
                <Activity size={16} />
                <span className="text-[10px] font-black uppercase">BMI 指数</span>
              </div>
              <div className="flex items-baseline gap-1">
                <span className="text-4xl font-black">{cur.bmi}</span>
              </div>
              <div className={`mt-2 text-[11px] font-black ${bmi?.color}`}>{bmi?.label}</div>
            </div>
          </div>

          {/* AI 助手 */}
          <div className="glass-card rounded-[28px] p-5 border-l-4 border-l-blue-500">
            <div className="flex items-center gap-2 mb-2">
              <Zap size={14} className="text-blue-500 fill-blue-500" />
              <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest">智能建议</span>
              {isAiLoading && <div className="w-1 h-1 bg-blue-500 rounded-full animate-ping" />}
            </div>
            <p className="text-sm font-bold text-gray-800 leading-tight">
              {aiAdvice || bmi?.advice || "继续坚持记录，健康从点滴开始。"}
            </p>
          </div>

          {/* 趋势图 */}
          <div className="glass-card rounded-[32px] p-6">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest flex items-center gap-2">
                <BarChart3 size={14} /> 趋势统计
              </h3>
              {chartMode !== 'recent' && years.length > 0 && (
                <select value={selectedYear} onChange={e => setSelectedYear(e.target.value)} className="bg-gray-100 px-2 py-1 rounded-lg text-[10px] font-black outline-none">
                  <option value="all">所有年份</option>
                  {years.map(y => <option key={y} value={y}>{y}年</option>)}
                </select>
              )}
            </div>
            <div className="bg-gray-100 p-1 rounded-2xl flex gap-1 mb-2">
              {['recent', 'monthly', 'yearly'].map(m => (
                <button key={m} onClick={() => setChartMode(m)} className={`flex-1 py-2 rounded-xl text-[10px] font-black transition-all ${chartMode === m ? 'bg-white shadow-sm text-blue-600' : 'text-gray-400'}`}>
                  {m === 'recent' ? '近况' : m === 'monthly' ? '月度' : '年度'}
                </button>
              ))}
            </div>
            <LocalChart records={records} mode={chartMode} year={selectedYear} />
          </div>

          {/* 历史记录列表 */}
          <div className="pt-4">
            <div className="flex justify-between items-end mb-4 px-2">
              <h3 className="text-xl font-black">打卡日志</h3>
              <span className="text-[10px] font-black text-gray-300">{records.length} 条记录</span>
            </div>
            <div className="space-y-3">
              {records.map(r => (
                <div key={r.id} className="bg-white rounded-[24px] p-4 flex items-center justify-between border border-gray-100 ios-active">
                  <div className="flex items-center gap-4">
                    <div className="w-10 h-10 bg-gray-50 rounded-xl flex items-center justify-center text-gray-300">
                      <Calendar size={18} />
                    </div>
                    <div>
                      <div className="flex items-center gap-2">
                        <span className="text-lg font-black">{r.weight}kg</span>
                        <span className={`text-[9px] px-1.5 py-0.5 rounded font-black ${getBMIInfo(r.bmi).bg} ${getBMIInfo(r.bmi).color}`}>BMI {r.bmi}</span>
                      </div>
                      <p className="text-[10px] text-gray-400 font-bold uppercase">{r.date} • {r.height}cm</p>
                    </div>
                  </div>
                  <button onClick={() => setRecords(prev => prev.filter(x => x.id !== r.id))} className="p-3 text-gray-200 active:text-red-500 transition-colors">
                    <Trash2 size={20} />
                  </button>
                </div>
              ))}
            </div>
          </div>
        </div>
      ) : (
        <div className="glass-card rounded-[40px] p-12 text-center mt-20 animate-ios-fade">
          <div className="w-20 h-20 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-6 text-blue-500">
            <Activity size={40} strokeWidth={2.5} />
          </div>
          <h2 className="text-xl font-black mb-2 tracking-tight">开启健康之旅</h2>
          <p className="text-gray-400 text-sm mb-10 font-medium">数据将永久保存在您的设备本地</p>
          <button onClick={() => setIsModalOpen(true)} className="bg-blue-600 text-white px-12 py-5 rounded-full font-black shadow-xl shadow-blue-200 active:scale-95 transition-all">
            首次录入
          </button>
        </div>
      )}

      {/* FAB */}
      <button 
        onClick={() => setIsModalOpen(true)}
        className="fixed bottom-10 left-1/2 -translate-x-1/2 w-16 h-16 bg-blue-600 text-white rounded-full shadow-2xl flex items-center justify-center active:scale-90 transition-all z-40"
      >
        <Plus size={32} strokeWidth={4} />
      </button>

      {/* 底部滑出模态框 */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/30 backdrop-blur-sm animate-ios-fade">
          <div className="bg-white w-full rounded-t-[44px] p-10 animate-ios-slide shadow-2xl max-w-md">
            <div className="flex justify-between items-center mb-10">
              <h2 className="text-2xl font-black tracking-tight">录入指标</h2>
              <button onClick={() => setIsModalOpen(false)} className="bg-gray-100 p-3 rounded-full text-gray-400 ios-active"><X size={20}/></button>
            </div>

            <div className="space-y-6">
              <div className="bg-gray-50 rounded-[28px] p-5">
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">记录日期</label>
                <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full bg-transparent text-xl font-black outline-none" />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="bg-gray-50 rounded-[28px] p-5">
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">身高 (cm)</label>
                  <input type="number" value={height} onChange={e => setHeight(e.target.value)} placeholder="170" className="w-full bg-transparent text-xl font-black outline-none" />
                </div>
                <div className="bg-gray-50 rounded-[28px] p-5">
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">体重 (kg)</label>
                  <input type="number" step="0.1" value={weight} onChange={e => setWeight(e.target.value)} placeholder="60.0" className="w-full bg-transparent text-xl font-black outline-none" />
                </div>
              </div>

              {height && weight && (
                <div className="p-5 bg-blue-50 rounded-[28px] flex justify-between items-center">
                  <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest">预估 BMI</span>
                  <span className="text-3xl font-black text-blue-700">{calculateBMI(parseFloat(height), parseFloat(weight))}</span>
                </div>
              )}

              <button 
                onClick={handleSave}
                disabled={!weight || !height}
                className="w-full py-6 bg-blue-600 text-white font-black rounded-[28px] shadow-xl shadow-blue-100 disabled:opacity-30 ios-active flex items-center justify-center gap-2 mt-4"
              >
                保存到档案 <ChevronRight size={20} strokeWidth={3} />
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

