@layer base {
  :root {
    --ios-bg: #F2F2F7;
    --ios-blue: #007AFF;
  }

  body {
    background-color: var(--ios-bg);
    margin: 0;
    padding: 0;
    -webkit-tap-highlight-color: transparent;
    -webkit-touch-callout: none;
    -webkit-user-select: none;
    user-select: none;
    font-family: -apple-system, BlinkMacSystemFont, "SF Pro Text", "Helvetica Neue", sans-serif;
    color: #1C1C1E;
    overscroll-behavior-y: none;
  }
}

@layer components {
  /* 80x80 避让区：确保左上角原生返回按钮不遮挡内容 */
  .safe-area-top-left {
    position: fixed;
    top: 0;
    left: 0;
    z-index: 100;
    width: 80px;
    height: 80px;
    pointer-events: none;
  }

  /* iOS 标准毛玻璃效果 */
  .glass-card {
    background-color: rgba(255, 255, 255, 0.8);
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
    border: 0.5px solid rgba(255, 255, 255, 0.4);
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05);
  }

  /* 原生缩放反馈 */
  .ios-active:active {
    transform: scale(0.96);
    opacity: 0.8;
    transition: all 0.1s ease-out;
  }

  /* 丝滑的滑入动画 */
  .animate-ios-slide {
    animation: iosSlide 0.5s cubic-bezier(0.1, 0.7, 0.1, 1) forwards;
  }

  .animate-ios-fade {
    animation: iosFade 0.4s ease-out forwards;
  }
}

@keyframes iosSlide {
  from { transform: translateY(100%); }
  to { transform: translateY(0); }
}

@keyframes iosFade {
  from { opacity: 0; }
  to { opacity: 1; }
}

/* 隐藏滚动条以增强 Native 感 */
::-webkit-scrollbar {
  display: none;
}

