import './style.css';
import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import { 
  Plus, Trash2, TrendingDown, TrendingUp, Activity, 
  Scale, Calendar, ChevronRight, Zap, BarChart3, X, Heart
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

const STORAGE_KEY = 'health_pro_db_v3';

const App = () => {
  const [records, setRecords] = useState<any[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [weight, setWeight] = useState('');
  const [height, setHeight] = useState('170');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [aiAdvice, setAiAdvice] = useState('');

  // 1. 初始化：从本地加载数据
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) setRecords(JSON.parse(saved));
  }, []);

  // 2. 自动保存 & AI 获取
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(records));
    if (records.length > 0) getAdvice();
  }, [records]);

  const getAdvice = async () => {
    if (!process.env.API_KEY || records.length === 0) return;
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const cur = records[0];
      const res = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `我是身高${cur.height}cm,体重${cur.weight}kg,BMI${cur.bmi}的用户。请用中文给一句15字内的极简健康口号。`
      });
      setAiAdvice(res.text);
    } catch (e) { console.error(e); }
  };

  const handleAdd = () => {
    const w = parseFloat(weight), h = parseFloat(height);
    if (!w || !h) return;
    const bmi = parseFloat((w / ((h / 100) ** 2)).toFixed(1));
    const newRecord = { id: Date.now(), date, height: h, weight: w, bmi };
    setRecords([newRecord, ...records].sort((a, b) => b.date.localeCompare(a.date)));
    setIsModalOpen(false);
    setWeight('');
  };

  const cur = records[0];
  const diff = records[1] ? (cur.weight - records[1].weight).toFixed(1) : '0';

  return (
    <div className="max-w-md mx-auto min-h-screen px-6 pb-32">
      {/* iOS 头部 */}
      <div className="safe-area-gap" />
      <header className="mb-8 flex items-center gap-3">
        <div className="bg-red-500 p-2 rounded-2xl shadow-lg shadow-red-200">
          <Heart className="text-white" size={24} fill="white" />
        </div>
        <div>
          <h1 className="text-3xl font-black tracking-tight">Health Pro</h1>
          <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">本机离线档案</p>
        </div>
      </header>

      {cur ? (
        <div className="space-y-6">
          {/* 指标卡片 */}
          <div className="grid grid-cols-2 gap-4">
            <div className="glass-card rounded-[32px] p-6 ios-active">
              <Scale className="text-blue-500 mb-3" size={20} />
              <div className="text-4xl font-black">{cur.weight}<span className="text-xs text-gray-300 ml-1">KG</span></div>
              <div className={`text-[10px] font-bold mt-2 ${Number(diff) > 0 ? 'text-red-500' : 'text-green-500'}`}>
                {Number(diff) > 0 ? '+' : ''}{diff}kg 变动
              </div>
            </div>
            <div className="glass-card rounded-[32px] p-6 ios-active">
              <Activity className="text-orange-500 mb-3" size={20} />
              <div className="text-4xl font-black">{cur.bmi}</div>
              <div className="text-[10px] font-bold text-gray-400 mt-2 uppercase">BMI 指数</div>
            </div>
          </div>

          {/* AI 建议 */}
          <div className="bg-blue-600 rounded-[28px] p-5 shadow-xl shadow-blue-100 flex items-start gap-3">
            <Zap className="text-yellow-300 fill-yellow-300 shrink-0" size={18} />
            <p className="text-white text-sm font-bold leading-tight">
              {aiAdvice || "录入更多数据，AI 将为你生成专属建议。"}
            </p>
          </div>

          {/* 历史列表 */}
          <div className="space-y-3">
            <h3 className="text-lg font-black px-1">打卡历史</h3>
            {records.map(r => (
              <div key={r.id} className="bg-white rounded-[24px] p-4 flex items-center justify-between shadow-sm ios-active">
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 bg-gray-50 rounded-xl flex items-center justify-center text-gray-400"><Calendar size={18}/></div>
                  <div>
                    <div className="font-black text-lg">{r.weight}kg <span className="text-[10px] text-gray-300 ml-1">BMI {r.bmi}</span></div>
                    <div className="text-[10px] text-gray-400 font-bold uppercase">{r.date}</div>
                  </div>
                </div>
                <button onClick={() => setRecords(records.filter(x => x.id !== r.id))} className="p-2 text-gray-200 active:text-red-500 transition-colors"><Trash2 size={20}/></button>
              </div>
            ))}
          </div>
        </div>
      ) : (
        <div className="text-center py-20">
          <div className="w-20 h-20 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-6 text-gray-300"><Activity size={40}/></div>
          <h2 className="text-xl font-black">暂无记录</h2>
          <p className="text-gray-400 text-sm mt-2">点击下方加号开始记录</p>
        </div>
      )}

      {/* FAB 按钮 */}
      <button onClick={() => setIsModalOpen(true)} className="fixed bottom-10 left-1/2 -translate-x-1/2 w-16 h-16 bg-black text-white rounded-full shadow-2xl flex items-center justify-center active:scale-90 transition-all z-50">
        <Plus size={32} strokeWidth={3} />
      </button>

      {/* 录入弹窗 */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-end bg-black/40 backdrop-blur-sm">
          <div className="bg-white w-full rounded-t-[40px] p-8 pb-12 shadow-2xl animate-ios-slide">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black">新记录</h2>
              <button onClick={() => setIsModalOpen(false)} className="bg-gray-100 p-2 rounded-full text-gray-400"><X size={20}/></button>
            </div>
            <div className="space-y-4">
              <div className="bg-gray-50 p-4 rounded-2xl">
                <label className="text-[10px] font-black text-gray-400 uppercase">日期</label>
                <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full bg-transparent font-black text-lg outline-none"/>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="bg-gray-50 p-4 rounded-2xl">
                  <label className="text-[10px] font-black text-gray-400 uppercase">身高(cm)</label>
                  <input type="number" value={height} onChange={e => setHeight(e.target.value)} className="w-full bg-transparent font-black text-lg outline-none"/>
                </div>
                <div className="bg-gray-50 p-4 rounded-2xl">
                  <label className="text-[10px] font-black text-gray-400 uppercase">体重(kg)</label>
                  <input type="number" value={weight} onChange={e => setWeight(e.target.value)} placeholder="0.0" className="w-full bg-transparent font-black text-lg outline-none"/>
                </div>
              </div>
              <button onClick={handleAdd} className="w-full py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl shadow-blue-100 mt-4 active:scale-95 transition-all">确认保存</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const root = ReactDOM.createRoot(document.getElementById('root')!);
root.render(<App />);

